// One HubSpot deal per approved opportunity. Pipeline: 'Opportunity Qualification'
// (the existing-customer 'need pipeline' from the workshops), stage 'Existing'.
const pipes=($('Get pipelines').first().json.results)||[];
let pipeId='2486071513', stageId=null;
const oq=pipes.find(p=>p.id===pipeId)||pipes.find(p=>/opportunity qualification/i.test(p.label))||pipes[0];
if(oq){pipeId=oq.id;const st=(oq.stages||[]).find(s=>/existing/i.test(s.label))||(oq.stages||[])[0];if(st)stageId=st.id;}
const r=$json;
const props={dealname:r.deal_name||'Second Brain opportunity',pipeline:pipeId};
if(stageId)props.dealstage=stageId;
if(r.networks_total!=null&&r.networks_total!=='')props.networks_score=Number(r.networks_total)||0;
const assoc=r.company_id?[{to:{id:String(r.company_id)},types:[{associationCategory:'HUBSPOT_DEFINED',associationTypeId:5}]}]:[];
return {json:{push_id:r.id,payload:{properties:props,associations:assoc}}};

const pushId=$('Build deal payload').item.json.push_id;
const q=s=>"'"+String(s).replace(/'/g,"''")+"'";
const dealId=$json.id||null;
const sql=dealId
 ? "UPDATE hubspot_pushes SET status='pushed', hubspot_deal_id="+q(dealId)+", pushed_at=now() WHERE id="+q(pushId)+";"
 : "UPDATE hubspot_pushes SET status='failed', error="+q(JSON.stringify($json).slice(0,400))+" WHERE id="+q(pushId)+";";
return {json:{sql}};
